1056→        if (assignmentErrorCode.get() == AssignorError.SHUTDOWN_REQUESTED.code()) {
1057→            final long now = time.milliseconds();
1058→            final long lastLogged = lastShutdownWarningTimestamp.get();
1059→            if (now - lastLogged >= 10_000L) {
1060→                if (lastShutdownWarningTimestamp.compareAndSet(lastLogged, now)) {
1061→                    log.warn("Detected that shutdown was requested. " +
